INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Invoice Generator', 'invoice-generator', 'Create a professional invoice online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional invoice online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"invoice_number","label":"Invoice No.","type":"text","required":true},{"name":"invoice_date","label":"Issue Date","type":"date","required":true},{"name":"due_date","label":"Due Date","type":"date","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"From (Your Business)","type":"party","required":true},{"name":"to_name","label":"Bill To","type":"party","required":true},{"name":"items","label":"Line Items","type":"line_items","required":true},{"name":"tax_rate","label":"Tax Rate (%)","type":"number","required":false},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"What should a professional invoice include to meet international standards?","a":"A compliant invoice should show a unique invoice number, issue date and due date, the full legal name and address of both the supplier and the customer, a clear description of goods or services with quantities and unit prices, the applicable tax (VAT/GST/sales tax) and tax registration numbers where required, the total amount due, the currency, and accepted payment methods. Invoxaco captures all of these and pulls your tax and bank details from your company profile automatically."},{"q":"Can I charge tax (VAT/GST/sales tax) and multiple currencies?","a":"Yes. You can set a tax rate for the whole invoice or per line item, add discounts and shipping, and choose the billing currency. The totals, subtotal and tax are calculated automatically."},{"q":"Can I download this Invoice as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Invoice suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Invoice Generator - Free Online Invoice Generator | Invoxaco', 'Generate a Invoice Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 1);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Receipt Generator', 'receipt-generator', 'Create a professional receipt online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional receipt online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"receipt_number","label":"Receipt No.","type":"text","required":true},{"name":"receipt_date","label":"Issue Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"Received By","type":"party","required":true},{"name":"to_name","label":"Received From","type":"party","required":true},{"name":"items","label":"Items / Services","type":"line_items","required":true},{"name":"payment_method","label":"Payment Method","type":"text","required":false},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"Is a receipt legally valid proof of payment?","a":"Yes. A receipt that identifies the payer and payee, the amount and currency, the date, what was paid for and the payment method is accepted internationally as proof that payment was received. Invoxaco records each of these fields."},{"q":"What is the difference between an invoice and a receipt?","a":"An invoice is a request for payment issued before payment; a receipt confirms that payment has already been received. Use the Invoice Generator to bill a customer and the Receipt Generator to acknowledge their payment."},{"q":"Can I download this Receipt as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Receipt suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Receipt Generator - Free Online Receipt Generator | Invoxaco', 'Generate a Receipt Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 2);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Credit Note Generator', 'credit-note-generator', 'Create a professional credit note online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional credit note online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"credit_note_number","label":"Credit Note No.","type":"text","required":true},{"name":"credit_note_date","label":"Issue Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"From (Your Business)","type":"party","required":true},{"name":"to_name","label":"Issued To","type":"party","required":true},{"name":"original_invoice_number","label":"Original Invoice Number","type":"text","required":false},{"name":"reason","label":"Reason for Credit","type":"textarea","required":true},{"name":"items","label":"Line Items","type":"line_items","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"When should I issue a credit note?","a":"Issue a credit note when you need to reduce or cancel a previously issued invoice — for example after a return, an overcharge, a discount agreed after invoicing, or a billing error. It creates an auditable record that reverses part or all of the original invoice."},{"q":"Should a credit note reference the original invoice?","a":"Yes. Best practice (and a requirement under most VAT/GST regimes) is to reference the original invoice number and date so the adjustment is traceable. Enter the original invoice reference in the notes or reference field."},{"q":"Can I download this Credit Note as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Credit Note suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Credit Note Generator - Free Online Credit Note Generator | Invoxaco', 'Generate a Credit Note Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 3);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Debit Note Generator', 'debit-note-generator', 'Create a professional debit note online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional debit note online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"debit_note_number","label":"Debit Note No.","type":"text","required":true},{"name":"debit_note_date","label":"Issue Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"From (Your Business)","type":"party","required":true},{"name":"to_name","label":"Issued To","type":"party","required":true},{"name":"original_invoice_number","label":"Original Invoice Number","type":"text","required":false},{"name":"reason","label":"Reason for Debit","type":"textarea","required":true},{"name":"items","label":"Line Items","type":"line_items","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"What is a debit note used for?","a":"A debit note is issued to increase the amount a customer owes, or by a buyer to a supplier to request a credit — for example for undercharged items, additional goods delivered, or returned purchases. It documents the adjustment for both parties'' records."},{"q":"How is a debit note different from an invoice?","a":"An invoice bills for an original sale; a debit note adjusts or supplements an existing transaction. It should reference the related invoice so the change is auditable."},{"q":"Can I download this Debit Note as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Debit Note suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Debit Note Generator - Free Online Debit Note Generator | Invoxaco', 'Generate a Debit Note Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 4);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Expense Report Generator', 'expense-report-generator', 'Create a professional expense report online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional expense report online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"report_title","label":"Report Title","type":"text","required":true,"default":"Expense Report"},{"name":"employee_name","label":"Employee / Claimant Name","type":"text","required":true},{"name":"employee_id","label":"Employee ID","type":"text","required":false},{"name":"department","label":"Department","type":"text","required":false},{"name":"manager_name","label":"Approving Manager","type":"text","required":false},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"items","label":"Expense Items","type":"line_items","required":true,"has_unit":true,"per_item_tax":true},{"name":"advance_received","label":"Advance / Float Received","type":"number","required":false},{"name":"purpose","label":"Business Purpose","type":"textarea","required":false,"default":"Expenses incurred in the course of authorized business activities on behalf of the company."},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Original receipts are attached for each line item in accordance with company expense policy."},{"name":"submitted_by_name","label":"Submitted By","type":"text","required":false},{"name":"submitted_by_signature","label":"Claimant Signature","type":"signature","required":false},{"name":"approved_by_name","label":"Approved By","type":"text","required":false},{"name":"approved_by_signature","label":"Approver Signature","type":"signature","required":false}]}', '[{"q":"What makes an expense report audit-ready?","a":"An audit-ready expense report itemises each expense with its date, category, amount and business purpose, references attached receipts, shows any advance or float received, and carries both the claimant''s and an approver''s sign-off. Invoxaco structures all of these so the report stands up to internal and tax audits."},{"q":"Can employees submit expenses in different currencies?","a":"Yes. Set the report currency and enter each line item accordingly. For multi-currency travel, convert to your reporting currency and note the rate used in the notes field."},{"q":"Can I download this Expense Report as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Expense Report suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Expense Report Generator - Free Online Expense Report Generator | Invoxaco', 'Generate a Expense Report Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 5);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Profit and Loss Statement Generator', 'profit-and-loss-statement-generator', 'Create a professional profit and loss statement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional profit and loss statement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"statement_title","label":"Statement Title","type":"text","required":true,"default":"Profit & Loss Statement"},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"revenue_items","label":"Revenue","type":"line_items","required":true},{"name":"cogs_items","label":"Cost of Goods Sold","type":"line_items","required":true},{"name":"operating_expenses","label":"Operating Expenses","type":"line_items","required":true},{"name":"other_items","label":"Other Income / (Expenses)","type":"line_items","required":true},{"name":"tax_expense","label":"Income Tax Expense","type":"number","required":false},{"name":"notes","label":"Notes to the Statement","type":"textarea","required":false,"default":"Figures are prepared on an accruals basis and are unaudited unless otherwise stated."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', '[{"q":"What does a profit and loss statement show?","a":"A profit and loss (income) statement summarises revenue, cost of goods sold, gross profit, operating expenses, and net profit or loss over a defined period. It is one of the three core financial statements used internationally to assess a business''s performance."},{"q":"Is this statement prepared under IFRS or US GAAP?","a":"The template uses a neutral, widely accepted income-statement structure compatible with both IFRS and US GAAP presentation. For statutory filing or audit, have your accountant confirm the presentation required in your jurisdiction."},{"q":"Can I download this Profit & Loss Statement as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Profit & Loss Statement suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Profit and Loss Statement Generator - Free Online Profit and Loss Statement Generator | Invoxaco', 'Generate a Profit and Loss Statement Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 6);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Balance Sheet Generator', 'balance-sheet-generator', 'Create a professional balance sheet online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional balance sheet online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"statement_title","label":"Statement Title","type":"text","required":true,"default":"Balance Sheet"},{"name":"as_of_date","label":"As of Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"current_assets","label":"Current Assets","type":"line_items","required":true},{"name":"non_current_assets","label":"Non-Current Assets","type":"line_items","required":true},{"name":"current_liabilities","label":"Current Liabilities","type":"line_items","required":true},{"name":"non_current_liabilities","label":"Non-Current Liabilities","type":"line_items","required":true},{"name":"equity","label":"Equity","type":"line_items","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"This statement of financial position is prepared on a going-concern basis and is unaudited unless otherwise stated."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', '[{"q":"What is a balance sheet and what must balance?","a":"A balance sheet (statement of financial position) lists a company''s assets, liabilities and equity at a point in time. It must always balance to the accounting equation: total assets = total liabilities + equity."},{"q":"Does this follow international presentation standards?","a":"Yes. The template groups items into current and non-current assets and liabilities plus equity, the structure used under both IFRS and US GAAP. Confirm any statutory note disclosures with your accountant for filing."},{"q":"Can I download this Balance Sheet as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Balance Sheet suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Balance Sheet Generator - Free Online Balance Sheet Generator | Invoxaco', 'Generate a Balance Sheet Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 7);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Cash Flow Statement Generator', 'cash-flow-statement-generator', 'Create a professional cash flow statement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional cash flow statement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"statement_title","label":"Statement Title","type":"text","required":true,"default":"Cash Flow Statement"},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"opening_balance","label":"Opening Cash Balance","type":"number","required":true},{"name":"operating_activities","label":"Cash Flows from Operating Activities","type":"line_items","required":true},{"name":"investing_activities","label":"Cash Flows from Investing Activities","type":"line_items","required":true},{"name":"financing_activities","label":"Cash Flows from Financing Activities","type":"line_items","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Prepared using the direct/indirect method as indicated; figures are unaudited unless otherwise stated."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', '[{"q":"What are the three sections of a cash flow statement?","a":"A cash flow statement is divided into operating activities (cash from core business), investing activities (purchase/sale of assets and investments), and financing activities (debt, equity and dividends). Together they reconcile opening and closing cash balances."},{"q":"Why is a cash flow statement important?","a":"Profit is not the same as cash. A cash flow statement shows whether a business is actually generating cash to meet its obligations, and is reviewed internationally by lenders, investors and auditors alongside the income statement and balance sheet."},{"q":"Can I download this Cash Flow Statement as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Cash Flow Statement suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Cash Flow Statement Generator - Free Online Cash Flow Statement Generator | Invoxaco', 'Generate a Cash Flow Statement Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 8);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Budget Proposal Generator', 'budget-proposal-generator', 'Create a professional budget proposal online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional budget proposal online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"organization_name","label":"Organization / Department","type":"text","required":true},{"name":"proposal_title","label":"Proposal Title","type":"text","required":true,"default":"Budget Proposal"},{"name":"prepared_for","label":"Prepared For","type":"text","required":false},{"name":"budget_period_from","label":"Budget Period From","type":"date","required":true},{"name":"budget_period_to","label":"Budget Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"objective","label":"Objective / Background","type":"textarea","required":false,"default":"This proposal sets out the estimated funding required to achieve the stated objectives for the budget period, with assumptions and justifications for each line."},{"name":"budget_items","label":"Budgeted Line Items","type":"line_items","required":true,"has_unit":true},{"name":"contingency_percent","label":"Contingency (%)","type":"number","required":false},{"name":"assumptions","label":"Key Assumptions","type":"textarea","required":false,"default":"Estimates are based on current pricing and prior-period actuals; material assumptions are noted against the relevant line items."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false},{"name":"approved_by","label":"Approved By","type":"text","required":false},{"name":"approved_by_signature","label":"Approver Signature","type":"signature","required":false}]}', '[{"q":"What should a strong budget proposal contain?","a":"A persuasive budget proposal states the objective, defines the budget period, itemises each cost with quantities and unit prices, adds a contingency, and documents the assumptions behind the numbers — all signed off by a preparer and an approver. This structure is expected by finance committees and grant funders internationally."},{"q":"Can I include a contingency and justify each cost?","a":"Yes. Add a contingency percentage and use the assumptions field to justify estimates. Clear justification significantly improves approval rates for departmental and project budgets."},{"q":"Can I download this Budget Proposal as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Budget Proposal suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Budget Proposal Generator - Free Online Budget Proposal Generator | Invoxaco', 'Generate a Budget Proposal Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 9);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Payment Receipt Generator', 'payment-receipt-generator', 'Create a professional payment receipt online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional payment receipt online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"receipt_number","label":"Receipt No.","type":"text","required":true},{"name":"receipt_date","label":"Issue Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"Received By","type":"party","required":true},{"name":"to_name","label":"Received From","type":"party","required":true},{"name":"payment_method","label":"Payment Method","type":"text","required":false},{"name":"items","label":"Payment For","type":"line_items","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"What should a payment receipt confirm?","a":"It should confirm the amount received, the currency, the date of payment, the payment method (cash, card, bank transfer, cheque), what the payment was for, and any remaining balance. This gives both parties a clear record for accounting and tax."},{"q":"Can I issue a receipt for a partial payment?","a":"Yes. Record the amount received and note the outstanding balance so both you and your customer have an accurate running record of the account."},{"q":"Can I download this Payment Receipt as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Payment Receipt suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Payment Receipt Generator - Free Online Payment Receipt Generator | Invoxaco', 'Generate a Payment Receipt Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 10);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Financial Statement Generator', 'financial-statement-generator', 'Create a professional financial statement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional financial statement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"statement_title","label":"Statement Title","type":"text","required":true,"default":"Financial Statement"},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"income_items","label":"Income","type":"line_items","required":true},{"name":"expense_items","label":"Expenses","type":"line_items","required":true},{"name":"assets_items","label":"Assets","type":"line_items","required":true},{"name":"liabilities_items","label":"Liabilities","type":"line_items","required":true},{"name":"notes","label":"Notes / Basis of Preparation","type":"textarea","required":false,"default":"These financial statements are prepared on an accruals basis using consistent accounting policies and are unaudited unless otherwise stated."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', '[{"q":"What is included in a set of financial statements?","a":"A complete set of financial statements typically includes an income statement, a statement of financial position (balance sheet), a cash flow statement and explanatory notes. This generator produces a consolidated summary suitable for management reporting, lenders and investors."},{"q":"Are these statements suitable for statutory filing?","a":"They provide a clear, internationally structured summary for management and stakeholders. For statutory or regulatory filing, have a qualified accountant prepare or review the statements to the exact standard (IFRS, US GAAP or local GAAP) required."},{"q":"Can I download this Financial Statement as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Financial Statement suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Financial Statement Generator - Free Online Financial Statement Generator | Invoxaco', 'Generate a Financial Statement Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 11);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Quotation Generator', 'quotation-generator', 'Create a professional quotation online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional quotation online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"quote_number","label":"Quote No.","type":"text","required":true},{"name":"quote_date","label":"Issue Date","type":"date","required":true},{"name":"valid_until","label":"Valid Until","type":"date","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"From (Your Business)","type":"party","required":true},{"name":"to_name","label":"Prepared For","type":"party","required":true},{"name":"items","label":"Line Items","type":"line_items","required":true,"has_unit":true,"per_item_discount":true,"per_item_tax":true},{"name":"tax_rate","label":"Tax Rate (%)","type":"number","required":false},{"name":"discount_type","label":"Discount Type","type":"select","required":false,"options":["fixed","percent"]},{"name":"discount_value","label":"Discount Value","type":"number","required":false},{"name":"shipping_cost","label":"Shipping Cost","type":"number","required":false},{"name":"installation_charges","label":"Installation Charges","type":"number","required":false},{"name":"delivery_charges","label":"Delivery Charges","type":"number","required":false},{"name":"training_charges","label":"Training Charges","type":"number","required":false},{"name":"support_charges","label":"Support Charges","type":"number","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false},{"name":"terms","label":"Terms and Conditions","type":"textarea","required":false}]}', '[{"q":"Is the Quotation Generator free to use?","a":"Yes, every Invoxaco plan includes access to the quotation tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download the quotation as PDF and Word?","a":"Yes. Every document you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file."},{"q":"Can I email the document directly to my client?","a":"Yes, Pro and Premium users can send any generated document as a PDF or DOCX email attachment directly from Invoxaco."}]', 1, 1, 'Quotation Generator - Free Online Quotation Generator | Invoxaco', 'Generate a Quotation Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 1);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Purchase Order Generator', 'purchase-order-generator', 'Create a professional purchase order online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional purchase order online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"po_number","label":"PO No.","type":"text","required":true},{"name":"po_date","label":"Issue Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"Buyer (Your Business)","type":"party","required":true},{"name":"to_name","label":"Vendor / Supplier","type":"party","required":true},{"name":"ship_to","label":"Ship To","type":"textarea","required":false},{"name":"items","label":"Line Items","type":"line_items","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"Is a purchase order a legally binding document?","a":"Once a supplier accepts a purchase order it generally forms a binding contract for the goods or services, quantities, prices and terms stated on it. A clear PO number, delivery date and agreed terms make it enforceable and are standard practice for procurement worldwide."},{"q":"What should every purchase order include?","a":"A unique PO number, the buyer and supplier details, an itemised list with quantities and agreed unit prices, the delivery address and date, payment terms, and any tax. Invoxaco captures all of these and lets you reuse them across orders."},{"q":"Can I download this Purchase Order as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Purchase Order suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Purchase Order Generator - Free Online Purchase Order Generator | Invoxaco', 'Generate a Purchase Order Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 2);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Sales Order Generator', 'sales-order-generator', 'Create a professional sales order online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional sales order online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"order_number","label":"Order No.","type":"text","required":true},{"name":"order_date","label":"Issue Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"From (Your Business)","type":"party","required":true},{"name":"to_name","label":"Sold To","type":"party","required":true},{"name":"ship_to","label":"Ship To","type":"textarea","required":false},{"name":"items","label":"Line Items","type":"line_items","required":true},{"name":"tax_rate","label":"Tax Rate (%)","type":"number","required":false},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"What is the purpose of a sales order?","a":"A sales order confirms a seller''s acceptance of a customer''s order and records exactly what will be supplied, at what price, and on what delivery and payment terms. It is the seller''s internal and customer-facing record that turns a quote or PO into a committed sale."},{"q":"How does a sales order relate to an invoice?","a":"The sales order confirms the order details; the invoice later requests payment for the goods or services delivered against it. Keeping the same reference on both keeps your order-to-cash records consistent."},{"q":"Can I download this Sales Order as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Sales Order suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Sales Order Generator - Free Online Sales Order Generator | Invoxaco', 'Generate a Sales Order Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 3);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Proforma Invoice Generator', 'proforma-invoice-generator', 'Create a professional proforma invoice online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional proforma invoice online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"proforma_number","label":"Proforma No.","type":"text","required":true},{"name":"proforma_date","label":"Issue Date","type":"date","required":true},{"name":"valid_until","label":"Valid Until","type":"date","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"From (Your Business)","type":"party","required":true},{"name":"to_name","label":"Buyer","type":"party","required":true},{"name":"items","label":"Line Items","type":"line_items","required":true},{"name":"tax_rate","label":"Tax Rate (%)","type":"number","required":false},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"What is a proforma invoice and when is it used?","a":"A proforma invoice is a preliminary bill of sale sent before goods or services are supplied, commonly used for quotations, advance-payment requests, and customs/import declarations in international trade. It states the expected price and terms but is not a demand for payment."},{"q":"Is a proforma invoice the same as a commercial invoice?","a":"No. A proforma is issued before the transaction is finalised and is not booked as a receivable; a commercial (tax) invoice is issued once the sale is confirmed and is the document used for accounting and tax."},{"q":"Can I download this Proforma Invoice as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Proforma Invoice suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Proforma Invoice Generator - Free Online Proforma Invoice Generator | Invoxaco', 'Generate a Proforma Invoice Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 4);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Delivery Note Generator', 'delivery-note-generator', 'Create a professional delivery note online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional delivery note online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"delivery_number","label":"Delivery No.","type":"text","required":true},{"name":"delivery_date","label":"Issue Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"From (Your Business)","type":"party","required":true},{"name":"to_name","label":"Deliver To","type":"party","required":true},{"name":"ship_to","label":"Ship To","type":"textarea","required":false},{"name":"items","label":"Items Delivered","type":"line_items","required":true},{"name":"carrier","label":"Carrier / Courier","type":"text","required":false},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"What is a delivery note used for?","a":"A delivery note (or dispatch/packing note) accompanies a shipment and lists the goods being delivered so the recipient can check them against their order. A signed delivery note is widely accepted proof that goods were received in good condition."},{"q":"Should the customer sign the delivery note?","a":"Yes. Having the recipient sign confirms delivery and condition of the goods, which protects both parties in the event of a later dispute about what was delivered."},{"q":"Can I download this Delivery Note as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Delivery Note suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Delivery Note Generator - Free Online Delivery Note Generator | Invoxaco', 'Generate a Delivery Note Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 5);
