l suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Sales Proposal Generator - Free Online Sales Proposal Generator | Invoxaco', 'Generate a Sales Proposal Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 6);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Price Quote Comparison Generator', 'price-quote-comparison-generator', 'Create a professional price quote comparison online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional price quote comparison online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"company_name","label":"Your Company","type":"text","required":true},{"name":"document_title","label":"Document Title","type":"text","required":true,"default":"Price Quote Comparison"},{"name":"prepared_for","label":"Prepared For","type":"text","required":false},{"name":"comparison_date","label":"Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"requirement","label":"Requirement / Scope","type":"textarea","required":false,"default":"This comparison evaluates supplier quotations received for the stated requirement on a like-for-like basis to support a transparent procurement decision."},{"name":"vendor_quotes","label":"Vendor Quotes","type":"line_items","required":true,"has_unit":true},{"name":"evaluation_criteria","label":"Evaluation Criteria","type":"textarea","required":false,"default":"Quotes are assessed on price, specification compliance, lead time, warranty, after-sales support and supplier track record."},{"name":"recommendation","label":"Recommendation","type":"textarea","required":false,"default":"Based on the evaluation criteria above, the recommended supplier offers the best overall value for the requirement."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', '[{"q":"Why use a price quote comparison?","a":"A structured comparison documents that competing quotations were evaluated on a fair, like-for-like basis — price, specification, lead time, warranty and support — which is best practice for procurement and is often required for audit or grant compliance."},{"q":"Can I compare more than two suppliers?","a":"Yes. Add a line for each supplier''s quote and use the evaluation and recommendation fields to record why the chosen supplier offers the best overall value, not simply the lowest price."},{"q":"Can I download this Price Quote Comparison as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Price Quote Comparison suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Price Quote Comparison Generator - Free Online Price Quote Comparison Generator | Invoxaco', 'Generate a Price Quote Comparison Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 7);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Discount Voucher Generator', 'discount-voucher-generator', 'Create a professional discount voucher online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional discount voucher online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"business_name","label":"Business Name","type":"text","required":true},{"name":"voucher_title","label":"Voucher Title","type":"text","required":true,"default":"Discount Voucher"},{"name":"voucher_code","label":"Voucher Code","type":"text","required":true},{"name":"discount_type","label":"Discount Type","type":"select","required":false,"options":["Percentage","Fixed Amount"],"default":"Percentage"},{"name":"discount_value","label":"Discount Value","type":"number","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"offer_description","label":"Offer Description","type":"textarea","required":false,"default":"Present this voucher at checkout to redeem the discount shown. One voucher per transaction unless otherwise stated."},{"name":"valid_from","label":"Valid From","type":"date","required":false},{"name":"valid_until","label":"Valid Until","type":"date","required":true},{"name":"terms","label":"Terms & Conditions","type":"textarea","required":false,"default":"This voucher has no cash value, cannot be combined with other offers unless stated, and is valid only within the dates shown. The issuer reserves the right to amend or withdraw the offer."}]}', '[{"q":"What should a discount voucher include to be valid?","a":"A redeemable voucher should show a unique code, the discount value or percentage, the valid-from and valid-until dates, and clear terms and conditions (such as one-per-customer or exclusions). These protect the business and set clear expectations for the customer."},{"q":"Can I create percentage or fixed-amount vouchers?","a":"Yes. Choose a percentage or a fixed amount, set the value and the validity window, and add any conditions. The voucher is branded with your business details and ready to print or share digitally."},{"q":"Can I download this Discount Voucher as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Discount Voucher suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Discount Voucher Generator - Free Online Discount Voucher Generator | Invoxaco', 'Generate a Discount Voucher Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 8);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Sales Agreement Generator', 'sales-agreement-generator', 'Create a professional sales agreement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional sales agreement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"agreement_date","label":"Agreement Date","type":"date","required":true},{"name":"seller","label":"Seller","type":"party","required":true},{"name":"buyer","label":"Buyer","type":"party","required":true},{"name":"item_description","label":"Item Description","type":"textarea","required":true},{"name":"sale_price","label":"Sale Price","type":"number","required":false},{"name":"payment_terms","label":"Payment Terms","type":"textarea","required":false},{"name":"background","label":"Background / Recitals","type":"textarea","required":false,"default":"This Agreement is entered into between the parties for the purpose described herein. Each party confirms that it has the full right, power, and authority to enter into this Agreement and to perform its obligations under it."},{"name":"confidentiality_clause","label":"Confidentiality","type":"textarea","required":false,"default":"Each party agrees to keep confidential all non-public information disclosed by the other party in connection with this Agreement, including trade secrets, customer data, financial information, and business processes, and shall not disclose such information to any third party without prior written consent, except as required by law."},{"name":"intellectual_property_clause","label":"Intellectual Property Rights","type":"textarea","required":false,"default":"Each party retains all rights, title, and interest in its pre-existing intellectual property. Ownership of any new intellectual property created specifically under this Agreement shall be as agreed in writing between the parties; absent such agreement, each party retains ownership of its own contributions."},{"name":"warranty_clause","label":"Warranty","type":"textarea","required":false,"default":"Except as expressly stated in this Agreement, each party provides its performance on an as-is basis with a limited warranty that services and deliverables will be performed in a professional and workmanlike manner consistent with industry standards."},{"name":"liability_clause","label":"Limitation of Liability","type":"textarea","required":false,"default":"To the maximum extent permitted by law, neither party''s total liability arising out of or relating to this Agreement shall exceed the total fees paid or payable under this Agreement in the twelve (12) months preceding the event giving rise to the claim, except for liability arising from gross negligence, willful misconduct, or breach of confidentiality obligations."},{"name":"indemnification_clause","label":"Indemnification","type":"textarea","required":false,"default":"Each party agrees to indemnify, defend, and hold harmless the other party from and against any third-party claims, damages, losses, or expenses (including reasonable legal fees) arising out of its breach of this Agreement, negligence, or willful misconduct."},{"name":"force_majeure_clause","label":"Force Majeure","type":"textarea","required":false,"default":"Neither party shall be liable for any failure or delay in performance due to causes beyond its reasonable control, including acts of war, natural disasters, government restrictions, or internet or utility outages."},{"name":"termination_clause","label":"Termination","type":"textarea","required":false,"default":"Either party may terminate this Agreement for convenience by providing thirty (30) days'' written notice to the other party. Either party may terminate immediately upon the other party''s material breach that remains uncured for fifteen (15) days after written notice, or upon the other party''s insolvency or bankruptcy."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":false,"default":"The parties shall first attempt to resolve any dispute arising out of this Agreement through good-faith negotiation. If the dispute is not resolved within thirty (30) days, the parties agree to submit the dispute to binding arbitration or, where the parties mutually agree, mediation, prior to pursuing court litigation, except where injunctive relief is required."},{"name":"assignment_clause","label":"Assignment","type":"textarea","required":false,"default":"Neither party may assign or transfer its rights or obligations under this Agreement without the prior written consent of the other party, except in connection with a merger, acquisition, or sale of substantially all of its assets."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement constitutes the entire agreement between the parties with respect to its subject matter and supersedes all prior or contemporaneous agreements, understandings, and communications, whether written or oral."},{"name":"severability_clause","label":"Severability","type":"textarea","required":false,"default":"If any provision of this Agreement is held to be invalid or unenforceable, the remaining provisions shall continue in full force and effect, and the invalid provision shall be deemed modified to the minimum extent necessary to make it enforceable."},{"name":"electronic_signature_clause","label":"Electronic Signature","type":"textarea","required":false,"default":"The parties agree that this Agreement may be executed electronically and that electronic signatures, including typed, drawn, or uploaded signatures, shall have the same legal effect as handwritten signatures."},{"name":"data_protection_clause","label":"Data Protection & Privacy","type":"textarea","required":false,"default":"Each party shall handle any personal data obtained in connection with this Agreement in accordance with applicable data protection laws (including, where applicable, GDPR, UK GDPR, CCPA, or PIPEDA) and shall implement reasonable safeguards against unauthorized access, use, or disclosure of such data."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"witness_name","label":"Witness Name (optional)","type":"text","required":false},{"name":"seller_signature","label":"Seller Signature","type":"signature","required":false},{"name":"buyer_signature","label":"Buyer Signature","type":"signature","required":false}]}', '[{"q":"Is the Sales Agreement Generator free to use?","a":"Yes, every Invoxaco plan includes access to the sales agreement tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download the sales agreement as PDF and Word?","a":"Yes. Every document you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file."},{"q":"Can I email the document directly to my client?","a":"Yes, Pro and Premium users can send any generated document as a PDF or DOCX email attachment directly from Invoxaco."}]', 1, 1, 'Sales Agreement Generator - Free Online Sales Agreement Generator | Invoxaco', 'Generate a Sales Agreement Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 9);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Order Confirmation Generator', 'order-confirmation-generator', 'Create a professional order confirmation online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional order confirmation online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"order_number","label":"Order No.","type":"text","required":true},{"name":"order_date","label":"Issue Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"from_name","label":"From (Your Business)","type":"party","required":true},{"name":"to_name","label":"Customer","type":"party","required":true},{"name":"items","label":"Line Items","type":"line_items","required":true},{"name":"expected_delivery_date","label":"Expected Delivery Date","type":"date","required":false},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for doing business with Us!"}]}', '[{"q":"What is an order confirmation?","a":"An order confirmation is sent by a seller to acknowledge that a customer''s order has been received and accepted, restating the items, prices, delivery date and terms. It reassures the customer and creates a shared record before fulfilment."},{"q":"How is it different from a sales order or invoice?","a":"An order confirmation acknowledges and accepts the order to the customer; a sales order is the seller''s internal commitment to fulfil it; an invoice later requests payment. Many businesses use the same reference across all three."},{"q":"Can I download this Order Confirmation as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Order Confirmation suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Order Confirmation Generator - Free Online Order Confirmation Generator | Invoxaco', 'Generate a Order Confirmation Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 10);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (2, 'Return Merchandise Authorization Generator', 'return-merchandise-authorization-generator', 'Create a professional return merchandise authorization online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional return merchandise authorization online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-graph-up-arrow', 'free', '{"fields":[{"name":"rma_number","label":"RMA No.","type":"text","required":true},{"name":"request_date","label":"Request Date","type":"date","required":true},{"name":"to_name","label":"Customer","type":"party","required":true},{"name":"original_order_number","label":"Original Order Number","type":"text","required":false},{"name":"items","label":"Items Being Returned","type":"line_items","required":true},{"name":"reason_for_return","label":"Reason for Return","type":"textarea","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false}]}', '[{"q":"What is an RMA and why issue one?","a":"A Return Merchandise Authorization (RMA) formally approves a customer''s return and assigns a tracking number, recording the reason for return, the items, and the resolution (refund, replacement or repair). It controls returns and provides an audit trail for warranty and accounting purposes."},{"q":"What should an RMA include?","a":"An RMA number, the original order/invoice reference, the customer''s details, the items being returned with reasons, the authorised resolution, and any return-shipping instructions. Invoxaco captures all of these on one clear document."},{"q":"Can I download this Return Merchandise Authorization as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Return Merchandise Authorization suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]', 1, 1, 'Return Merchandise Authorization Generator - Free Online Return Merchandise Authorization Generator | Invoxaco', 'Generate a Return Merchandise Authorization Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 11);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (3, 'Non-Disclosure Agreement Generator', 'non-disclosure-agreement-generator', 'Create a professional non-disclosure agreement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional non-disclosure agreement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-bank', 'free', '{"fields":[{"name":"agreement_date","label":"Agreement Date","type":"date","required":true},{"name":"disclosing_party","label":"Disclosing Party","type":"party","required":true},{"name":"receiving_party","label":"Receiving Party","type":"party","required":true},{"name":"purpose","label":"Purpose","type":"textarea","required":true},{"name":"term_years","label":"Term (Years)","type":"number","required":false},{"name":"background","label":"Background / Recitals","type":"textarea","required":false,"default":"This Agreement is entered into between the parties for the purpose described herein. Each party confirms that it has the full right, power, and authority to enter into this Agreement and to perform its obligations under it."},{"name":"confidentiality_clause","label":"Confidentiality","type":"textarea","required":false,"default":"Each party agrees to keep confidential all non-public information disclosed by the other party in connection with this Agreement, including trade secrets, customer data, financial information, and business processes, and shall not disclose such information to any third party without prior written consent, except as required by law."},{"name":"intellectual_property_clause","label":"Intellectual Property Rights","type":"textarea","required":false,"default":"Each party retains all rights, title, and interest in its pre-existing intellectual property. Ownership of any new intellectual property created specifically under this Agreement shall be as agreed in writing between the parties; absent such agreement, each party retains ownership of its own contributions."},{"name":"warranty_clause","label":"Warranty","type":"textarea","required":false,"default":"Except as expressly stated in this Agreement, each party provides its performance on an as-is basis with a limited warranty that services and deliverables will be performed in a professional and workmanlike manner consistent with industry standards."},{"name":"liability_clause","label":"Limitation of Liability","type":"textarea","required":false,"default":"To the maximum extent permitted by law, neither party''s total liability arising out of or relating to this Agreement shall exceed the total fees paid or payable under this Agreement in the twelve (12) months preceding the event giving rise to the claim, except for liability arising from gross negligence, willful misconduct, or breach of confidentiality obligations."},{"name":"indemnification_clause","label":"Indemnification","type":"textarea","required":false,"default":"Each party agrees to indemnify, defend, and hold harmless the other party from and against any third-party claims, damages, losses, or expenses (including reasonable legal fees) arising out of its breach of this Agreement, negligence, or willful misconduct."},{"name":"force_majeure_clause","label":"Force Majeure","type":"textarea","required":false,"default":"Neither party shall be liable for any failure or delay in performance due to causes beyond its reasonable control, including acts of war, natural disasters, government restrictions, or internet or utility outages."},{"name":"termination_clause","label":"Termination","type":"textarea","required":false,"default":"Either party may terminate this Agreement for convenience by providing thirty (30) days'' written notice to the other party. Either party may terminate immediately upon the other party''s material breach that remains uncured for fifteen (15) days after written notice, or upon the other party''s insolvency or bankruptcy."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":false,"default":"The parties shall first attempt to resolve any dispute arising out of this Agreement through good-faith negotiation. If the dispute is not resolved within thirty (30) days, the parties agree to submit the dispute to binding arbitration or, where the parties mutually agree, mediation, prior to pursuing court litigation, except where injunctive relief is required."},{"name":"assignment_clause","label":"Assignment","type":"textarea","required":false,"default":"Neither party may assign or transfer its rights or obligations under this Agreement without the prior written consent of the other party, except in connection with a merger, acquisition, or sale of substantially all of its assets."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement constitutes the entire agreement between the parties with respect to its subject matter and supersedes all prior or contemporaneous agreements, understandings, and communications, whether written or oral."},{"name":"severability_clause","label":"Severability","type":"textarea","required":false,"default":"If any provision of this Agreement is held to be invalid or unenforceable, the remaining provisions shall continue in full force and effect, and the invalid provision shall be deemed modified to the minimum extent necessary to make it enforceable."},{"name":"electronic_signature_clause","label":"Electronic Signature","type":"textarea","required":false,"default":"The parties agree that this Agreement may be executed electronically and that electronic signatures, including typed, drawn, or uploaded signatures, shall have the same legal effect as handwritten signatures."},{"name":"data_protection_clause","label":"Data Protection & Privacy","type":"textarea","required":false,"default":"Each party shall handle any personal data obtained in connection with this Agreement in accordance with applicable data protection laws (including, where applicable, GDPR, UK GDPR, CCPA, or PIPEDA) and shall implement reasonable safeguards against unauthorized access, use, or disclosure of such data."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"additional_terms","label":"Additional Terms & Conditions","type":"textarea","required":false},{"name":"witness_name","label":"Witness Name (optional)","type":"text","required":false},{"name":"disclosing_party_signature","label":"Disclosing Party Signature","type":"signature","required":false},{"name":"receiving_party_signature","label":"Receiving Party Signature","type":"signature","required":false}]}', '[{"q":"Is the Non-Disclosure Agreement Generator free to use?","a":"Yes, every Invoxaco plan includes access to the non-disclosure agreement tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download the non-disclosure agreement as PDF and Word?","a":"Yes. Every document you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file."},{"q":"Can I email the document directly to my client?","a":"Yes, Pro and Premium users can send any generated document as a PDF or DOCX email attachment directly from Invoxaco."}]', 1, 1, 'Non-Disclosure Agreement Generator - Free Online Non-Disclosure Agreement Generator | Invoxaco', 'Generate a Non-Disclosure Agreement Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 1);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (3, 'Contract Agreement Generator', 'contract-agreement-generator', 'Create a professional contract agreement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional contract agreement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-bank', 'free', '{"fields":[{"name":"contract_date","label":"Contract Date","type":"date","required":true},{"name":"party_a","label":"Party A","type":"party","required":true},{"name":"party_b","label":"Party B","type":"party","required":true},{"name":"scope","label":"Scope","type":"textarea","required":true},{"name":"payment_terms","label":"Payment Terms","type":"textarea","required":false},{"name":"start_date","label":"Start Date","type":"date","required":false},{"name":"end_date","label":"End Date","type":"date","required":false},{"name":"background","label":"Background / Recitals","type":"textarea","required":false,"default":"This Agreement is entered into between the parties for the purpose described herein. Each party confirms that it has the full right, power, and authority to enter into this Agreement and to perform its obligations under it."},{"name":"confidentiality_clause","label":"Confidentiality","type":"textarea","required":false,"default":"Each party agrees to keep confidential all non-public information disclosed by the other party in connection with this Agreement, including trade secrets, customer data, financial information, and business processes, and shall not disclose such information to any third party without prior written consent, except as required by law."},{"name":"intellectual_property_clause","label":"Intellectual Property Rights","type":"textarea","required":false,"default":"Each party retains all rights, title, and interest in its pre-existing intellectual property. Ownership of any new intellectual property created specifically under this Agreement shall be as agreed in writing between the parties; absent such agreement, each party retains ownership of its own contributions."},{"name":"warranty_clause","label":"Warranty","type":"textarea","required":false,"default":"Except as expressly stated in this Agreement, each party provides its performance on an as-is basis with a limited warranty that services and deliverables will be performed in a professional and workmanlike manner consistent with industry standards."},{"name":"liability_clause","label":"Limitation of Liability","type":"textarea","required":false,"default":"To the maximum extent permitted by law, neither party''s total liability arising out of or relating to this Agreement shall exceed the total fees paid or payable under this Agreement in the twelve (12) months preceding the event giving rise to the claim, except for liability arising from gross negligence, willful misconduct, or breach of confidentiality obligations."},{"name":"indemnification_clause","label":"Indemnification","type":"textarea","required":false,"default":"Each party agrees to indemnify, defend, and hold harmless the other party from and against any third-party claims, damages, losses, or expenses (including reasonable legal fees) arising out of its breach of this Agreement, negligence, or willful misconduct."},{"name":"force_majeure_clause","label":"Force Majeure","type":"textarea","required":false,"default":"Neither party shall be liable for any failure or delay in performance due to causes beyond its reasonable control, including acts of war, natural disasters, government restrictions, or internet or utility outages."},{"name":"termination_clause","label":"Termination","type":"textarea","required":false,"default":"Either party may terminate this Agreement for convenience by providing thirty (30) days'' written notice to the other party. Either party may terminate immediately upon the other party''s material breach that remains uncured for fifteen (15) days after written notice, or upon the other party''s insolvency or bankruptcy."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":false,"default":"The parties shall first attempt to resolve any dispute arising out of this Agreement through good-faith negotiation. If the dispute is not resolved within thirty (30) days, the parties agree to submit the dispute to binding arbitration or, where the parties mutually agree, mediation, prior to pursuing court litigation, except where injunctive relief is required."},{"name":"assignment_clause","label":"Assignment","type":"textarea","required":false,"default":"Neither party may assign or transfer its rights or obligations under this Agreement without the prior written consent of the other party, except in connection with a merger, acquisition, or sale of substantially all of its assets."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement constitutes the entire agreement between the parties with respect to its subject matter and supersedes all prior or contemporaneous agreements, understandings, and communications, whether written or oral."},{"name":"severability_clause","label":"Severability","type":"textarea","required":false,"default":"If any provision of this Agreement is held to be invalid or unenforceable, the remaining provisions shall continue in full force and effect, and the invalid provision shall be deemed modified to the minimum extent necessary to make it enforceable."},{"name":"electronic_signature_clause","label":"Electronic Signature","type":"textarea","required":false,"default":"The parties agree that this Agreement may be executed electronically and that electronic signatures, including typed, drawn, or uploaded signatures, shall have the same legal effect as handwritten signatures."},{"name":"data_protection_clause","label":"Data Protection & Privacy","type":"textarea","required":false,"default":"Each party shall handle any personal data obtained in connection with this Agreement in accordance with applicable data protection laws (including, where applicable, GDPR, UK GDPR, CCPA, or PIPEDA) and shall implement reasonable safeguards against unauthorized access, use, or disclosure of such data."},{"name":"non_solicitation_clause","label":"Non-Solicitation","type":"textarea","required":false,"default":"During the term of this Agreement and for twelve (12) months thereafter, neither party shall solicit for hire any employee or contractor of the other party, nor solicit the other party''s clients or customers for competing purposes, without prior written consent."},{"name":"change_request_clause","label":"Change Requests","type":"textarea","required":false,"default":"Any changes to the scope described in this Agreement must be agreed in writing by both parties, including any associated adjustments to fees or timelines, before such changes take effect."},{"name":"insurance_clause","label":"Insurance","type":"textarea","required":false,"default":"Where applicable, each party shall maintain insurance coverage appropriate to its obligations under this Agreement and shall provide proof of such coverage upon the other party''s reasonable request."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"witness_name","label":"Witness Name (optional)","type":"text","required":false},{"name":"party_a_signature","label":"Party A Signature","type":"signature","required":false},{"name":"party_b_signature","label":"Party B Signature","type":"signature","required":false}]}', '[{"q":"Is the Contract Agreement Generator free to use?","a":"Yes, every Invoxaco plan includes access to the contract agreement tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download the contract agreement as PDF and Word?","a":"Yes. Every document you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file."},{"q":"Can I email the document directly to my client?","a":"Yes, Pro and Premium users can send any generated document as a PDF or DOCX email attachment directly from Invoxaco."}]', 1, 1, 'Contract Agreement Generator - Free Online Contract Agreement Generator | Invoxaco', 'Generate a Contract Agreement Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 2);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (3, 'Service Agreement Generator', 'service-agreement-generator', 'Create a professional service agreement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional service agreement online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-bank', 'free', '{"fields":[{"name":"agreement_date","label":"Agreement Date","type":"date","required":true},{"name":"service_provider","label":"Service Provider","type":"party","required":true},{"name":"client","label":"Client","type":"party","required":true},{"name":"scope_of_services","label":"Scope of Services","type":"textarea","required":true},{"name":"payment_terms","label":"Payment Terms","type":"textarea","required":false},{"name":"start_date","label":"Start Date","type":"date","required":false},{"name":"end_date","label":"End Date","type":"date","required":false},{"name":"background","label":"Background / Recitals","type":"textarea","required":false,"default":"This Agreement is entered into between the parties for the purpose described herein. Each party confirms that it has the full right, power, and authority to enter into this Agreement and to perform its obligations under it."},{"name":"confidentiality_clause","label":"Confidentiality","type":"textarea","required":false,"default":"Each party agrees to keep confidential all non-public information disclosed by the other party in connection with this Agreement, including trade secrets, customer data, financial information, and business processes, and shall not disclose such information to any third party without prior written consent, except as required by law."},{"name":"intellectual_property_clause","label":"Intellectual Property Rights","type":"textarea","required":false,"default":"Each party retains all rights, title, and interest in its pre-existing intellectual property. Ownership of any new intellectual property created specifically under this Agreement shall be as agreed in writing between the parties; absent such agreement, each party retains ownership of its own contributions."},{"name":"warranty_clause","label":"Warranty","type":"textarea","required":false,"default":"Except as expressly stated in this Agreement, each party provides its performance on an as-is basis with a limited warranty that services and deliverables will be performed in a professional and workmanlike manner consistent with industry standards."},{"name":"liability_clause","label":"Limitation of Liability","type":"textarea","required":false,"default":"To the maximum extent permitted by law, neither party''s total liability arising out of or relating to this Agreement shall exceed the total fees paid or payable under this Agreement in the twelve (12) months preceding the event giving rise to the claim, except for liability arising from gross negligence, willful misconduct, or breach of confidentiality obligations."},{"name":"indemnification_clause","label":"Indemnification","type":"textarea","required":false,"default":"Each party agrees to indemnify, defend, and hold harmless the other party from and against any third-party claims, damages, losses, or expenses (including reasonable legal fees) arising out of its breach of this Agreement, negligence, or willful misconduct."},{"name":"force_majeure_clause","label":"Force Majeure","type":"textarea","required":false,"default":"Neither party shall be liable for any failure or delay in performance due to causes beyond its reasonable control, including acts of war, natural disasters, government restrictions, or internet or utility outages."},{"name":"termination_clause","label":"Termination","type":"textarea","required":false,"default":"Either party may terminate this Agreement for convenience by providing thirty (30) days'' written notice to the other party. Either party may terminate immediately upon the other party''s material breach that remains uncured for fifteen (15) days after written notice, or upon the other party''s insolvency or bankruptcy."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":false,"default":"The parties shall first attempt to resolve any dispute arising out of this Agreement through good-faith negotiation. If the dispute is not resolved within thirty (30) days, the parties agree to submit the dispute to binding arbitration or, where the parties mutually agree, mediation, prior to pursuing court litigation, except where injunctive relief is required."},{"name":"assignment_clause","label":"Assignment","type":"textarea","required":false,"default":"Neither party may assign or transfer its rights or obligations under this Agreement without the prior written consent of the other party, except in connection with a merger, acquisition, or sale of substantially all of its assets."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement constitutes the entire agreement between the parties with respect to its subject matter and supersedes all prior or contemporaneous agreements, understandings, and communications, whether written or oral."},{"name":"severability_clause","label":"Severability","type":"textarea","required":false,"default":"If any provision of this Agreement is held to be invalid or unenforceable, the remaining provisions shall continue in full force and effect, and the invalid provision shall be deemed modified to the minimum extent necessary to make it enforceable."},{"name":"electronic_signature_clause","label":"Electronic Signature","type":"textarea","required":false,"default":"The parties agree that this Agreement may be executed electronically and that electronic signatures, including typed, drawn, or uploaded signatures, shall have the same legal effect as handwritten signatures."},{"name":"data_protection_clause","label":"Data Protection & Privacy","type":"textarea","required":false,"default":"Each party shall handle any personal data obtained in connection with this Agreement in accordance with applicable data protection laws (including, where applicable, GDPR, UK GDPR, CCPA, or PIPEDA) and shall implement reasonable safeguards against unauthorized access, use, or disclosure of such data."},{"name":"non_solicitation_clause","label":"Non-Solicitation","type":"textarea","required":false,"default":"During the term of this Agreement and for twelve (12) months thereafter, neither party shall solicit for hire any employee or contractor of the other party, nor solicit the other party''s clients or customers for competing purposes, without prior written consent."},{"name":"change_request_clause","label":"Change Requests","type":"textarea","required":false,"default":"Any changes to the scope described in this Agreement must be agreed in writing by both parties, including any associated adjustments to fees or timelines, before such changes take effect."},{"name":"insurance_clause","label":"Insurance","type":"textarea","required":false,"default":"Where applicable, each party shall maintain insurance coverage appropriate to its obligations under this Agreement and shall provide proof of such coverage upon the other party''s reasonable request."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"witness_name","label":"Witness Name (optional)","type":"text","required":false},{"name":"service_provider_signature","label":"Service Provider Signature","type":"signature","required":false},{"name":"client_signature","label":"Client Signature","type":"signature","required":false}]}', '[{"q":"Is the Service Agreement Generator free to use?","a":"Yes, every Invoxaco plan includes access to the service agreement tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download the service agreement as PDF and Word?","a":"Yes. Every document you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file."},{"q":"Can I email the document directly to my client?","a":"Yes, Pro and Premium users can send any generated document as a PDF or DOCX email attachment directly from Invoxaco."}]', 1, 1, 'Service Agreement Generator - Free Online Service Agreement Generator | Invoxaco', 'Generate a Service Agreement Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 3);
