INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (3, 'Licensing Agreement Generator', 'licensing-agreement-generator', 'Create a professional licensing agreement online in minutes — license a brand, patent, or other property for royalty or fee, preview instantly, and download as PDF or DOCX.', 'Create a professional licensing agreement online in minutes — license a brand, patent, or other property for royalty or fee, preview instantly, and download as PDF or DOCX.', 'bi-award', 'free', '{"fields":[{"name":"agreement_date","label":"Agreement Date","type":"date","required":true},{"name":"licensor","label":"Licensor","type":"party","required":true},{"name":"licensee","label":"Licensee","type":"party","required":true},{"name":"licensed_property_description","label":"Description of Licensed Property (Brand, Patent, Trademark, etc.)","type":"textarea","required":true},{"name":"royalty_terms","label":"Royalty / Fee Terms","type":"textarea","required":false},{"name":"territory","label":"Licensed Territory","type":"text","required":false},{"name":"start_date","label":"Start Date","type":"date","required":false},{"name":"end_date","label":"End Date","type":"date","required":false},{"name":"background","label":"Background / Recitals","type":"textarea","required":false,"default":"This Agreement is entered into between the parties for the purpose described herein. Each party confirms that it has the full right, power, and authority to enter into this Agreement and to perform its obligations under it."},{"name":"confidentiality_clause","label":"Confidentiality","type":"textarea","required":false,"default":"Each party agrees to keep confidential all non-public information disclosed by the other party in connection with this Agreement, including trade secrets, customer data, financial information, and business processes, and shall not disclose such information to any third party without prior written consent, except as required by law."},{"name":"intellectual_property_clause","label":"Intellectual Property Rights","type":"textarea","required":false,"default":"Each party retains all rights, title, and interest in its pre-existing intellectual property. Ownership of any new intellectual property created specifically under this Agreement shall be as agreed in writing between the parties; absent such agreement, each party retains ownership of its own contributions."},{"name":"warranty_clause","label":"Warranty","type":"textarea","required":false,"default":"Except as expressly stated in this Agreement, each party provides its performance on an as-is basis with a limited warranty that services and deliverables will be performed in a professional and workmanlike manner consistent with industry standards."},{"name":"liability_clause","label":"Limitation of Liability","type":"textarea","required":false,"default":"To the maximum extent permitted by law, neither party''s total liability arising out of or relating to this Agreement shall exceed the total fees paid or payable under this Agreement in the twelve (12) months preceding the event giving rise to the claim, except for liability arising from gross negligence, willful misconduct, or breach of confidentiality obligations."},{"name":"indemnification_clause","label":"Indemnification","type":"textarea","required":false,"default":"Each party agrees to indemnify, defend, and hold harmless the other party from and against any third-party claims, damages, losses, or expenses (including reasonable legal fees) arising out of its breach of this Agreement, negligence, or willful misconduct."},{"name":"force_majeure_clause","label":"Force Majeure","type":"textarea","required":false,"default":"Neither party shall be liable for any failure or delay in performance due to causes beyond its reasonable control, including acts of war, natural disasters, government restrictions, or internet or utility outages."},{"name":"termination_clause","label":"Termination","type":"textarea","required":false,"default":"Either party may terminate this Agreement for convenience by providing thirty (30) days'' written notice to the other party. Either party may terminate immediately upon the other party''s material breach that remains uncured for fifteen (15) days after written notice, or upon the other party''s insolvency or bankruptcy."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":false,"default":"The parties shall first attempt to resolve any dispute arising out of this Agreement through good-faith negotiation. If the dispute is not resolved within thirty (30) days, the parties agree to submit the dispute to binding arbitration or, where the parties mutually agree, mediation, prior to pursuing court litigation, except where injunctive relief is required."},{"name":"assignment_clause","label":"Assignment","type":"textarea","required":false,"default":"Neither party may assign or transfer its rights or obligations under this Agreement without the prior written consent of the other party, except in connection with a merger, acquisition, or sale of substantially all of its assets."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement constitutes the entire agreement between the parties with respect to its subject matter and supersedes all prior or contemporaneous agreements, understandings, and communications, whether written or oral."},{"name":"severability_clause","label":"Severability","type":"textarea","required":false,"default":"If any provision of this Agreement is held to be invalid or unenforceable, the remaining provisions shall continue in full force and effect, and the invalid provision shall be deemed modified to the minimum extent necessary to make it enforceable."},{"name":"electronic_signature_clause","label":"Electronic Signature","type":"textarea","required":false,"default":"The parties agree that this Agreement may be executed electronically and that electronic signatures, including typed, drawn, or uploaded signatures, shall have the same legal effect as handwritten signatures."},{"name":"data_protection_clause","label":"Data Protection & Privacy","type":"textarea","required":false,"default":"Each party shall handle any personal data obtained in connection with this Agreement in accordance with applicable data protection laws (including, where applicable, GDPR, UK GDPR, CCPA, or PIPEDA) and shall implement reasonable safeguards against unauthorized access, use, or disclosure of such data."},{"name":"non_solicitation_clause","label":"Non-Solicitation","type":"textarea","required":false,"default":"During the term of this Agreement and for twelve (12) months thereafter, neither party shall solicit for hire any employee or contractor of the other party, nor solicit the other party''s clients or customers for competing purposes, without prior written consent."},{"name":"change_request_clause","label":"Change Requests","type":"textarea","required":false,"default":"Any changes to the scope described in this Agreement must be agreed in writing by both parties, including any associated adjustments to fees or timelines, before such changes take effect."},{"name":"insurance_clause","label":"Insurance","type":"textarea","required":false,"default":"Where applicable, each party shall maintain insurance coverage appropriate to its obligations under this Agreement and shall provide proof of such coverage upon the other party''s reasonable request."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"additional_terms","label":"Additional Terms & Conditions","type":"textarea","required":false},{"name":"witness_name","label":"Witness Name (optional)","type":"text","required":false},{"name":"licensor_signature","label":"Licensor Signature","type":"signature","required":false},{"name":"licensee_signature","label":"Licensee Signature","type":"signature","required":false}]}', '[{"q":"Is the Licensing Agreement Generator free to use?","a":"Yes, every Invoxaco plan includes access to this tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Is this for software licensing too?","a":"For software specifically, the dedicated Software License Agreement Generator includes fields tailored to license types and software descriptions."},{"q":"Can I set up royalty payments based on sales?","a":"Yes, describe a percentage-of-sales or other royalty structure in the Royalty / Fee Terms field."}]', 1, 1, 'Licensing Agreement Generator - Free Online Licensing Agreement Generator | Invoxaco', 'Create a professional licensing agreement online in minutes — license a brand, patent, or other property for royalty or fee, preview instantly, and download as PDF or DOCX.', 23);
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (4, 'Internship Agreement Generator', 'internship-agreement-generator', 'Create a professional internship agreement online in minutes — define role, duration, and stipend, preview instantly, and download as PDF or DOCX.', 'Create a professional internship agreement online in minutes — define role, duration, and stipend, preview instantly, and download as PDF or DOCX.', 'bi-mortarboard', 'free', '{"fields":[{"name":"agreement_date","label":"Agreement Date","type":"date","required":true},{"name":"company","label":"Company","type":"party","required":true},{"name":"intern","label":"Intern","type":"party","required":true},{"name":"role_description","label":"Internship Role & Responsibilities","type":"textarea","required":true},{"name":"start_date","label":"Start Date","type":"date","required":false},{"name":"end_date","label":"End Date","type":"date","required":false},{"name":"stipend","label":"Stipend / Compensation (if any)","type":"text","required":false},{"name":"work_schedule","label":"Work Schedule","type":"text","required":false},{"name":"background","label":"Background / Recitals","type":"textarea","required":false,"default":"This Agreement is entered into between the parties for the purpose described herein. Each party confirms that it has the full right, power, and authority to enter into this Agreement and to perform its obligations under it."},{"name":"confidentiality_clause","label":"Confidentiality","type":"textarea","required":false,"default":"Each party agrees to keep confidential all non-public information disclosed by the other party in connection with this Agreement, including trade secrets, customer data, financial information, and business processes, and shall not disclose such information to any third party without prior written consent, except as required by law."},{"name":"intellectual_property_clause","label":"Intellectual Property Rights","type":"textarea","required":false,"default":"Each party retains all rights, title, and interest in its pre-existing intellectual property. Ownership of any new intellectual property created specifically under this Agreement shall be as agreed in writing between the parties; absent such agreement, each party retains ownership of its own contributions."},{"name":"warranty_clause","label":"Warranty","type":"textarea","required":false,"default":"Except as expressly stated in this Agreement, each party provides its performance on an as-is basis with a limited warranty that services and deliverables will be performed in a professional and workmanlike manner consistent with industry standards."},{"name":"liability_clause","label":"Limitation of Liability","type":"textarea","required":false,"default":"To the maximum extent permitted by law, neither party''s total liability arising out of or relating to this Agreement shall exceed the total fees paid or payable under this Agreement in the twelve (12) months preceding the event giving rise to the claim, except for liability arising from gross negligence, willful misconduct, or breach of confidentiality obligations."},{"name":"indemnification_clause","label":"Indemnification","type":"textarea","required":false,"default":"Each party agrees to indemnify, defend, and hold harmless the other party from and against any third-party claims, damages, losses, or expenses (including reasonable legal fees) arising out of its breach of this Agreement, negligence, or willful misconduct."},{"name":"force_majeure_clause","label":"Force Majeure","type":"textarea","required":false,"default":"Neither party shall be liable for any failure or delay in performance due to causes beyond its reasonable control, including acts of war, natural disasters, government restrictions, or internet or utility outages."},{"name":"termination_clause","label":"Termination","type":"textarea","required":false,"default":"Either party may terminate this Agreement for convenience by providing thirty (30) days'' written notice to the other party. Either party may terminate immediately upon the other party''s material breach that remains uncured for fifteen (15) days after written notice, or upon the other party''s insolvency or bankruptcy."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":false,"default":"The parties shall first attempt to resolve any dispute arising out of this Agreement through good-faith negotiation. If the dispute is not resolved within thirty (30) days, the parties agree to submit the dispute to binding arbitration or, where the parties mutually agree, mediation, prior to pursuing court litigation, except where injunctive relief is required."},{"name":"assignment_clause","label":"Assignment","type":"textarea","required":false,"default":"Neither party may assign or transfer its rights or obligations under this Agreement without the prior written consent of the other party, except in connection with a merger, acquisition, or sale of substantially all of its assets."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement constitutes the entire agreement between the parties with respect to its subject matter and supersedes all prior or contemporaneous agreements, understandings, and communications, whether written or oral."},{"name":"severability_clause","label":"Severability","type":"textarea","required":false,"default":"If any provision of this Agreement is held to be invalid or unenforceable, the remaining provisions shall continue in full force and effect, and the invalid provision shall be deemed modified to the minimum extent necessary to make it enforceable."},{"name":"electronic_signature_clause","label":"Electronic Signature","type":"textarea","required":false,"default":"The parties agree that this Agreement may be executed electronically and that electronic signatures, including typed, drawn, or uploaded signatures, shall have the same legal effect as handwritten signatures."},{"name":"data_protection_clause","label":"Data Protection & Privacy","type":"textarea","required":false,"default":"Each party shall handle any personal data obtained in connection with this Agreement in accordance with applicable data protection laws (including, where applicable, GDPR, UK GDPR, CCPA, or PIPEDA) and shall implement reasonable safeguards against unauthorized access, use, or disclosure of such data."},{"name":"non_solicitation_clause","label":"Non-Solicitation","type":"textarea","required":false,"default":"During the term of this Agreement and for twelve (12) months thereafter, neither party shall solicit for hire any employee or contractor of the other party, nor solicit the other party''s clients or customers for competing purposes, without prior written consent."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"additional_terms","label":"Additional Terms & Conditions","type":"textarea","required":false},{"name":"witness_name","label":"Witness Name (optional)","type":"text","required":false},{"name":"company_signature","label":"Company Representative Signature","type":"signature","required":false},{"name":"intern_signature","label":"Intern Signature","type":"signature","required":false}]}', '[{"q":"Is the Internship Agreement Generator free to use?","a":"Yes, every Invoxaco plan includes access to this tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Does this agreement work for unpaid internships?","a":"Yes, leave the Stipend field blank or note ''unpaid'' — check local labor law requirements for unpaid internships in your jurisdiction."},{"q":"Does it include a non-compete clause?","a":"No, this agreement intentionally omits a non-compete clause since restricting an intern''s future employment is rarely appropriate or enforceable. It does include confidentiality and non-solicitation clauses."}]', 1, 1, 'Internship Agreement Generator - Free Online Internship Agreement Generator | Invoxaco', 'Create a professional internship agreement online in minutes — define role, duration, and stipend, preview instantly, and download as PDF or DOCX.', 14);
