INSERT INTO seo_settings (page_key, meta_title, meta_description, robots) VALUES ('features', 'Features - Invoxaco', 'Explore Invoxaco features: 110+ document generators, PDF/DOCX export, email sending, client management, team collaboration, and white-label branding.', 'index,follow');
INSERT INTO seo_settings (page_key, meta_title, meta_description, robots) VALUES ('generators', 'All Document Generators - Invoxaco', 'Browse 110+ free document generators for invoices, contracts, HR, real estate, construction, marketing, and startup paperwork.', 'index,follow');
